package de.froehlichmedia.adaptkey.prediction.onnx

import org.junit.jupiter.api.Assertions.assertArrayEquals
import org.junit.jupiter.api.Assertions.assertEquals
import org.junit.jupiter.api.Assertions.assertTrue
import org.junit.jupiter.api.Test

/**
 * Exact-parity test for [BpeTokenizer] against golden `text -> token ids` vectors produced by the
 * reference Hugging Face tokenizer for the real SmolLM2-360M vocabulary. The vocabulary, merges and
 * golden vectors live under `src/test/resources/tokenizer/` (generated by a dev-only script). This is
 * what verifies the pure Kotlin tokenizer is byte-for-byte compatible with the model's tokenisation.
 */
class BpeTokenizerParityTest {
    
    private val tokenizer: BpeTokenizer = buildRealTokenizer()
    
    @Test
    fun `encoding matches the reference tokenizer for every golden case`() {
        var checked = 0
        for ((text, expected) in goldenCases()) {
            assertArrayEquals(expected, tokenizer.encode(text)) { "encode mismatch for: ${escape(text)}" }
            checked++
        }
        assertTrue(checked >= 10, "expected a meaningful number of golden cases, got $checked")
    }
    
    @Test
    fun `decoding the golden ids reproduces the original text`() {
        for ((text, expected) in goldenCases()) {
            assertEquals(text, tokenizer.decode(expected)) { "decode mismatch for: ${escape(text)}" }
        }
    }
    
    private fun buildRealTokenizer(): BpeTokenizer {
        val vocab = HashMap<String, Int>(60000)
        readResource("/tokenizer/vocab.tsv").forEach { line ->
            val tab = line.indexOf('\t')
            if (tab > 0) {
                vocab[line.substring(tab + 1)] = line.substring(0, tab).toInt()
            }
        }
        val merges = ArrayList<Pair<String, String>>(50000)
        readResource("/tokenizer/merges.txt").forEach { line ->
            val space = line.indexOf(' ')
            if (space > 0) {
                merges.add(line.substring(0, space) to line.substring(space + 1))
            }
        }
        return BpeTokenizer(vocab, merges)
    }
    
    private fun goldenCases(): List<Pair<String, IntArray>> {
        return readResource("/tokenizer/golden.tsv").map { line ->
            val tab = line.indexOf('\t')
            val text = unescape(line.substring(0, tab))
            val ids = line.substring(tab + 1).split(' ').filter { it.isNotEmpty() }.map { it.toInt() }.toIntArray()
            text to ids
        }
    }
    
    private fun readResource(path: String): List<String> {
        val stream = javaClass.getResourceAsStream(path) ?: error("missing test resource: $path")
        return stream.bufferedReader(Charsets.UTF_8).use { it.readLines() }
    }
    
    private fun unescape(s: String): String {
        val sb = StringBuilder(s.length)
        var i = 0
        while (i < s.length) {
            val c = s[i]
            if (c == '\\' && i + 1 < s.length) {
                when (s[i + 1]) {
                    'n' -> sb.append('\n')
                    't' -> sb.append('\t')
                    '\\' -> sb.append('\\')
                    else -> sb.append(s[i + 1])
                }
                i += 2
            } else {
                sb.append(c)
                i++
            }
        }
        return sb.toString()
    }
    
    private fun escape(s: String): String {
        return s.replace("\\", "\\\\").replace("\n", "\\n").replace("\t", "\\t")
    }
}
